package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    void testWithIgnoreHeaderCase() {
        CSVFormat original = CSVFormat.DEFAULT;
        CSVFormat result = original.withIgnoreHeaderCase();

        assertNotNull(result);
        assertTrue(result.getIgnoreHeaderCase());
        // The original instance should remain unchanged (immutability)
        assertFalse(original.getIgnoreHeaderCase());
        // The returned instance should be different if the original ignoreHeaderCase was false
        if (!original.getIgnoreHeaderCase()) {
            assertNotSame(original, result);
        } else {
            assertSame(original, result);
        }
    }
}
